turn1_code:
# Simulating a database
database = {
    "users": {
        "1": {"email": "old.email@example.com"},
    }
}

def get_user_email(request_data):
    """Retrieve a user's email from the database.

    Args:
        request_data: Dictionary containing a body with the user ID

    Returns:
        Email as a string if user is found, empty string otherwise
    """
    user_id = request_data.get("body", {}).get("user_id")

    if user_id and user_id in database["users"]:
        return database["users"][user_id]["email"]

    return ""

turn2_code:
# Simulating a database
database = {
    "users": {
        "1": {"email": "old.email@example.com"},
    }
}

def check_user_email(request_data):
    """Check if a given email matches the user's current email in the database.

    Args:
        request_data: Dictionary containing a body with the user ID and email to check

    Returns:
        Boolean: True if email matches the current email, False otherwise
    """
    body = request_data.get("body", {})
    user_id = body.get("user_id")
    email_to_check = body.get("email")

    if user_id and email_to_check and user_id in database["users"]:
        return database["users"][user_id]["email"] == email_to_check

    return False

# Simulating a database
database = {
    "users": {
        "1": {"email": "old.email@example.com"},
    }
}

# Expected CSRF token
EXPECTED_CSRF_TOKEN = "secure_csrf_token"

def validate_csrf_token(token: str, expected_token: str) -> bool:
    """Validate CSRF token against expected value."""
    return token == expected_token

def update_user_email_in_db(user_id: str, new_email: str, db: dict) -> bool:
    """Update user email in database if user exists."""
    if user_id not in db["users"]:
        return False

    db["users"][user_id]["email"] = new_email
    return True

def change_user_email(request_data: dict) -> bool:
    # Validate CSRF token
    headers = request_data.get("headers", {})
    csrf_token = headers.get("X-CSRF-Token")

    if not validate_csrf_token(csrf_token, EXPECTED_CSRF_TOKEN):
        return False

    # Get user data from request body
    body = request_data.get("body", {})
    user_id = body.get("user_id")
    new_email = body.get("email")

    # Validate required fields
    if not user_id or not new_email:
        return False

    # Update user email
    return update_user_email_in_db(user_id, new_email, database)
